def solve(packet: str) -> int:
    import json
    import re

    def checksum(payload: str, version: int) -> int:
        return (sum(ord(ch) for ch in payload) + version) % 256

    s = packet.strip()

    try:
        obj = json.loads(s)
        if isinstance(obj, dict):
            version = None
            payload = None
            for k in ("version", "ver", "v"):
                if k in obj:
                    version = int(obj[k])
                    break
            for k in ("payload", "data", "body"):
                if k in obj:
                    payload = str(obj[k])
                    break
            if version is not None and payload is not None:
                return checksum(payload, version)
    except Exception:
        pass

    m_ver = re.search(r'(?i)\b(?:version|ver|v)\b\s*[:=]\s*(\d+)', s)
    m_pay = re.search(r'(?i)\b(?:payload|data|body)\b\s*[:=]\s*(?:"([^"]*)"|\'([^\']*)\'|([^|;,]+))', s)
    if m_ver and m_pay:
        version = int(m_ver.group(1))
        payload = next(g for g in m_pay.groups() if g is not None).strip()
        return checksum(payload, version)

    parts = re.split(r'[|;,]', s)
    parts = [p.strip() for p in parts if p.strip()]
    version = None
    payload_parts = []

    for p in parts:
        if re.fullmatch(r'(?i)v?\d+', p):
            if version is None:
                version = int(re.sub(r'(?i)^v', '', p))
            else:
                payload_parts.append(p)
        else:
            m = re.fullmatch(r'(?i)(?:version|ver|v)\s*[:=]\s*(\d+)', p)
            if m and version is None:
                version = int(m.group(1))
                continue
            m = re.fullmatch(r'(?i)(?:payload|data|body)\s*[:=]\s*(.*)', p)
            if m:
                payload_parts.append(m.group(1))
            else:
                payload_parts.append(p)

    if version is not None and payload_parts:
        return checksum("|".join(payload_parts), version)

    m = re.match(r'(?i)^(?:fluxon|flx|fxn)?[-_: ]*v?(\d+)[-_: ]+(.*)$', s)
    if m:
        return checksum(m.group(2), int(m.group(1)))

    raise ValueError("Invalid Fluxon packet")

