                if found is not None:
                    return found
        elif isinstance(obj, list):
            for item in obj:
                found = find_value(item, keys)
                if found is not None:
                    return found
        return None

    def parse_version(value: Any) -> Optional[float]:
        if isinstance(value, bool) or value is None:
