        if value is None:
            return True
        if isinstance(value, bool):
            return value
        if isinstance(value, (int, float)) and not isinstance(value, bool):
            return value != 0
        if isinstance(value, str):
            s = value.strip().lower()
            if s in {"true", "yes", "y", "1", "valid", "ok", "pass", "passed"}:
                return True
            if s in {"false", "no", "n", "0", "invalid", "bad", "fail", "failed"}:
                return False
        return False

